const e=JSON.parse('{"key":"v-23231fd3","path":"/ai-tools/Claude%20code%E5%BF%AB%E9%80%9F%E4%B8%8A%E6%89%8B.html","title":"Claude code快速上手","lang":"zh-CN","frontmatter":{"title":"Claude code快速上手","isTimeLine":true,"date":"2025-11-28T00:00:00.000Z","category":["AI工具"],"tag":["AI工具"]},"headers":[{"level":3,"title":"是什么？","slug":"是什么","link":"#是什么","children":[]},{"level":3,"title":"安装","slug":"安装","link":"#安装","children":[]},{"level":3,"title":"Claude Code 入门","slug":"claude-code-入门","link":"#claude-code-入门","children":[]},{"level":3,"title":"Claude Code 使用","slug":"claude-code-使用","link":"#claude-code-使用","children":[]}],"git":{"createdTime":1773286516000,"updatedTime":1773286516000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":3.38,"words":1014},"filePathRelative":"ai-tools/Claude code快速上手.md","localizedDate":"2025年11月28日","excerpt":"<h3> 是什么？</h3>\\n<ol>\\n<li>Calude Code 是由 Anthropic 开发的官方 CLI 工具，用于协助用户处理软件工程任务。 Anthropic 发现了Cursor的成功后，开发了Claude Code作为Cursor的竞品。</li>\\n<li>Claude是完全通过终端进行交互的，其中内置了多种工具，比如文件操作、搜索等。可以理解自然语言并转化为相应的命令执行。</li>\\n</ol>\\n<h3> 安装</h3>\\n<h4> Kimi K2API key获取</h4>\\n<ol>\\n<li>Kimi K2新模型遵循Anthropic协议，这代表着其可以顺利接入Claude Code，并且无需任何路由代理，只需要配置好URL与API即可直接使用。</li>\\n<li>直接来到Moonshot官网获取自己的<code>API key</code>，注册后新建<code>API key</code>，然后将Moonshot的url以及<code>API key</code>设置进环境变量的系统变量中。<code>ANTHROPIC_API_KEY：API key</code> <code>ANTHROPIC_BASE_URL：https://api.moonshot.cn/anthropic/</code></li>\\n</ol>"}');export{e as data};
